import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', 
    location: '', 
    startDate: '', 
    endDate: '', 
    description: '', 
    importantNotes: '',
    price: '', 
    status: 'Available' 
  });

  useEffect(() => {
    if (editingTour) {
      // 確保日期格式符合 HTML input type="date" (YYYY-MM-DD)
      const formattedTour = { ...editingTour };
      if (editingTour.startDate) formattedTour.startDate = editingTour.startDate.split('T')[0];
      if (editingTour.endDate) formattedTour.endDate = editingTour.endDate.split('T')[0];
      setFormData(formattedTour);
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!user?.token) return alert("Please login again.");

    try {
      const config = { headers: { Authorization: `Bearer ${user.token}` } };
      const { _id, __v, createdAt, updatedAt, ...payload } = formData;

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, payload, config);
      } else {
        await axiosInstance.post('/api/tours', payload, config);
      }
      alert('Saved successfully!');
      onSuccess();
    } catch (error) {
      alert('Save error: ' + (error.response?.data?.message || 'Check Server'));
    }
  };

  const handleDelete = async () => {
    if (!window.confirm("Are you sure to delete this?")) return;
    try {
      await axiosInstance.delete(`/api/tours/${editingTour._id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      alert('Deleted!');
      onSuccess();
    } catch (error) {
      console.error(error);
      alert('Delete failed. Make sure you are logged in as Admin.');
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-white font-sans">
      {/* Header */}
      <div className="flex justify-between items-center p-5 border-b sticky top-0 bg-white z-10">
        <button type="button" onClick={onClose} className="text-2xl text-gray-400">←</button>
        <h1 className="text-lg font-black text-gray-800">{editingTour ? 'Edit Tour' : 'Add Tour Package'}</h1>
        <button type="button" onClick={onClose} className="text-2xl">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6 flex-1 overflow-y-auto pb-32">
        {/* Title */}
        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Tour Title</label>
          <input type="text" placeholder="Enter title" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-400 outline-none" required />
        </div>

        {/* Location */}
        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Location</label>
          <input type="text" placeholder="Enter location" value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-400 outline-none" />
        </div>

        {/* Dates */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Start Date</label>
            <input type="date" value={formData.startDate} onChange={e => setFormData({...formData, startDate: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl text-gray-500" />
          </div>
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">End Date</label>
            <input type="date" value={formData.endDate} onChange={e => setFormData({...formData, endDate: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl text-gray-500" />
          </div>
        </div>

        {/* Description & Notes */}
        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">What is it about</label>
          <textarea placeholder="Enter description" rows="3" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-400 outline-none" />
        </div>

        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Important Notes</label>
          <textarea placeholder="Enter important notes" rows="2" value={formData.importantNotes} onChange={e => setFormData({...formData, importantNotes: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-400 outline-none" />
        </div>

        {/* Image Upload UI */}
        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Upload cover picture</label>
          <div className="border-2 border-dashed border-gray-100 rounded-[32px] p-10 text-center bg-gray-50">
             <div className="text-4xl mb-2 grayscale">☁️</div>
             <p className="font-bold text-gray-700 text-sm">Click to upload cover picture</p>
             <p className="text-[10px] text-gray-400 mt-1 uppercase">SVG, PNG, JPG (MAX. 5MB)</p>
          </div>
        </div>

        {/* Price & Status */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Price (AUD)</label>
            <input type="number" value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl" required />
          </div>
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Status</label>
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl">
               <option value="Available">Available</option>
               <option value="Sold Out">Sold Out</option>
            </select>
          </div>
        </div>

        {/* Buttons */}
        <div className="pt-4 space-y-3">
          <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-5 rounded-[24px] shadow-xl shadow-emerald-100 active:scale-95 transition">
            {editingTour ? 'Update Changes' : 'Submit'}
          </button>

          {editingTour && (
            <button type="button" onClick={handleDelete} className="w-full text-red-500 font-bold py-2 hover:bg-red-50 rounded-xl transition">
              Delete Tour Package
            </button>
          )}
        </div>
      </form>
    </div>
  );
};

export default TourForm;
